#include<bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    cin >> n >> m;

    multimap<pair<string, string>, bool> customers;
    for(int i = 0; i < n; i++) {
        string language, skill;
        cin >> language >> skill;
        customers.insert({{language, skill}, true});
    }

    for(int i = 0; i < m; i++) {
        string language, skill;
        cin >> language >> skill;
        auto it = customers.find({language, skill});
        if(it != customers.end()) {
            customers.erase(it);
        }
    }

    cout << customers.size() << "\n";
    return 0;
}

